name: Approve Workflows

on:
  pull_request_target:
    types:
      - labeled
      - synchronize
    branches:
      - main
      - 'release-**'

jobs:
  approve:
    runs-on: ubuntu-latest
    permissions:
      actions: write
    steps:
      - name: Check and approve workflows
        uses: actions/github-script@v7
        with:
          script: |
            const { owner, repo } = context.repo;
            const prNumber = context.payload.pull_request.number;

            // Check if PR has ok-to-test label or is from a collaborator
            const labels = context.payload.pull_request.labels.map(l => l.name);
            const hasOkToTest = labels.includes('ok-to-test');

            if (!hasOkToTest) {
              console.log('PR does not have ok-to-test label, skipping approval');
              return;
            }

            // List workflow runs that need approval
            const runs = await github.rest.actions.listWorkflowRunsForRepo({
              owner,
              repo,
              event: 'pull_request_target',
              status: 'action_required'
            });

            // Approve each workflow run
            for (const run of runs.data.workflow_runs) {
              if (run.pull_requests.some(pr => pr.number === prNumber)) {
                console.log(`Approving workflow run ${run.id}`);
                await github.rest.actions.approveWorkflowRun({
                  owner,
                  repo,
                  run_id: run.id
                });
              }
            }

