)

type ErrorResponse struct {
	Error   string `json:"error"`
	Code    string `json:"code,omitempty"`
	Message string `json:"message,omitempty"`
}

func handleAgentRuntimeCreate(c *gin.Context) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error:   "invalid request",
			Message: err.Error(),
		})
		return
	}

	if err := req.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error:   "validation failed",
			Message: err.Error(),
		})
		return
	}

	ctx := c.Request.Context()
	resp, err := createSandbox(ctx, types.AgentRuntimeKind, req.Name, req.Namespace, true, nil)
	if err != nil {
		handleSandboxCreateError(c, err)
		return
	}

	c.JSON(http.StatusOK, resp)
}

func handleCodeInterpreterCreate(c *gin.Context) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error:   "invalid request",
			Message: err.Error(),
		})
		return
	}

	if err := req.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error:   "validation failed",
			Message: err.Error(),
		})
		return
	}

	ctx := c.Request.Context()
	resp, err := createSandbox(ctx, types.CodeInterpreterKind, req.Name, req.Namespace, true, nil)
	if err != nil {
		handleSandboxCreateError(c, err)
		return
	}

	c.JSON(http.StatusOK, resp)
}

func handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "sessionId is required",
		})
		return
	}

	ctx := c.Request.Context()
	sandboxInfo, err := store.Storage().GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			c.JSON(http.StatusNotFound, ErrorResponse{
				Error: "sandbox not found",
			})
			return
		}
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to get sandbox",
		})
		return
	}

	k8sClient, err := NewK8sClient()
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to create k8s client",
		})
		return
	}

	var client dynamic.Interface
	if k8sClient.dynamicClient != nil {
		client = k8sClient.dynamicClient
	} else {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "dynamic client not available",
		})
		return
	}

	timeout := 30 * time.Second
	if err := deleteSandboxCR(ctx, client, sandboxInfo.SandboxNamespace, sandboxInfo.Name, sandboxInfo.Kind, timeout); err != nil {
		klog.Errorf("Failed to delete sandbox %s: %v", sessionID, err)
	}

	if err := store.Storage().DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		klog.Errorf("Failed to delete sandbox from store: %v", err)
	}

	c.JSON(http.StatusOK, gin.H{
		"message": "Sandbox deleted successfully",
	})
}

func createSandbox(ctx context.Context, kind, name, namespace string, enableAuth bool, userClient dynamic.Interface) (*types.CreateSandboxResponse, error) {
	placeholderSandbox := &types.SandboxInfo{
		SessionID: "pending",
		Kind:      kind,
		Name:      name,
		Status:    "pending",
	}

	if err := store.Storage().StoreSandbox(ctx, placeholderSandbox); err != nil {
		klog.Errorf("Failed to store sandbox: %v", err)
	}

	var sandboxInfo *types.SandboxInfo
	var err error

	switch kind {
	case types.AgentRuntimeKind:
		sandboxInfo, _, err = buildAgentRuntimeSandbox(ctx, &types.CreateSandboxRequest{
			Kind:      kind,
			Name:      name,
			Namespace: namespace,
		}, nil)
	case types.CodeInterpreterKind:
		sandboxInfo, _, err = buildCodeInterpreterSandbox(ctx, &types.CreateSandboxRequest{
			Kind:      kind,
			Name:      name,
			Namespace: namespace,
		}, nil)
	default:
		return nil, errors.NewBadRequest("unknown kind: " + kind)
	}

	if err != nil {
		return nil, err
	}

	return &types.CreateSandboxResponse{
		SessionID:   sandboxInfo.SessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	}, nil
}

func handleSandboxCreateError(c *gin.Context, err error) {
	if errors.IsNotFound(err) {
		c.JSON(http.StatusNotFound, ErrorResponse{
			Error:   "not found",
			Message: err.Error(),
		})
		return
	}

	if errors.IsBadRequest(err) {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error:   "bad request",
			Message: err.Error(),
		})
		return
	}

	klog.Errorf("Sandbox creation failed: %v", err)
	c.JSON(http.StatusInternalServerError, ErrorResponse{
		Error:   "internal server error",
		Message: err.Error(),
	})
}

func jsonResponse(c *gin.Context, status int, data interface{}) {
	c.Header("Content-Type", "application/json")
	c.JSON(status, data)
}

func writeJSON(w http.ResponseWriter, status int, data interface{}) error {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	return json.NewEncoder(w).Encode(data)
}

