package workloadmanager

import (
	"context"
	"fmt"
	"os"
	"time"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
	"k8s.io/apimachinery/pkg/util/uuid"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const (
	IdentitySecretName      = "picod-router-identity"
	PublicKeyDataKey        = "public.pem"
	IdentitySecretNamespace = "AGENTCUBE_NAMESPACE"
)

func buildAgentRuntimeSandbox(ctx context.Context, req *types.CreateSandboxRequest, ar interface{}) (*types.SandboxInfo, *unstructured.Unstructured, error) {
	sessionID := string(uuid.NewUUID())
	name := req.Name
	namespace := req.Namespace

	ports := []TargetPort{
		{
			Name:     "http",
			Port:     8080,
			Protocol: ProtocolTypeHTTP,
		},
	}

	template := &SandboxTemplate{
		Spec: map[string]interface{}{
			"containers": []map[string]interface{}{
				{
					"name":  "agent",
					"image": "ghcr.io/volcano-sh/agent:latest",
				},
			},
		},
	}

	sandbox := buildSandboxObject(name, namespace, sessionID, ports, template, DefaultSandboxTTL, DefaultSandboxIdleTimeout)

	sandboxInfo := &types.SandboxInfo{
		Kind:             types.AgentRuntimeKind,
		SandboxID:        string(sandbox.GetUID()),
		SandboxNamespace: namespace,
		Name:             name,
		SessionID:        sessionID,
		Status:           "pending",
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
	}

	return sandboxInfo, sandbox, nil
}

func buildCodeInterpreterSandbox(ctx context.Context, req *types.CreateSandboxRequest, ci interface{}) (*types.SandboxInfo, *unstructured.Unstructured, error) {
	sessionID := string(uuid.NewUUID())
	name := req.Name
	namespace := req.Namespace

	warmPoolSize := int32(0)
	authMode := "picod"

	if warmPoolSize > 0 {
		claim := &unstructured.Unstructured{
			Object: map[string]interface{}{
				"apiVersion": "extensions.agents.x-k8s.io/v1alpha1",
				"kind":       "SandboxClaim",
				"metadata": map[string]interface{}{
					"name":      name,
					"namespace": namespace,
					"labels": map[string]interface{}{
						SessionIdLabelKey: sessionID,
					},
				},
				"spec": map[string]interface{}{
					"templateName": name,
					"ttl":          DefaultSandboxTTL.String(),
				},
			},
		}

		sandboxInfo := &types.SandboxInfo{
			Kind:             types.CodeInterpreterKind,
			SandboxID:        string(uuid.NewUUID()),
			SandboxNamespace: namespace,
			Name:             name,
			SessionID:        sessionID,
			Status:           "pending",
			CreatedAt:        time.Now(),
			ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		}

		return sandboxInfo, claim, nil
	}

	ports := []TargetPort{
		{
			Name:     "http",
			Port:     8080,
			Protocol: ProtocolTypeHTTP,
		},
	}

	template := &SandboxTemplate{
		Spec: map[string]interface{}{
			"containers": []map[string]interface{}{
				{
					"name":  "picod",
					"image": "ghcr.io/volcano-sh/picod:latest",
					"env": []map[string]string{
						{
							"name":  "PICOD_AUTH_PUBLIC_KEY",
							"value": getPublicKeyFromEnv(),
						},
					},
				},
			},
		},
	}

	sandbox := buildSandboxObject(name, namespace, sessionID, ports, template, DefaultSandboxTTL, DefaultSandboxIdleTimeout)

	sandboxInfo := &types.SandboxInfo{
		Kind:             types.CodeInterpreterKind,
		SandboxID:        string(sandbox.GetUID()),
		SandboxNamespace: namespace,
		Name:             name,
		SessionID:        sessionID,
		Status:           "pending",
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		EntryPoints:      buildEntryPoints(name, namespace, ports),
	}

	return sandboxInfo, sandbox, nil
}

func buildSandboxObject(name, namespace, sessionID string, ports []TargetPort, template *SandboxTemplate, ttl, idleTimeout time.Duration) *unstructured.Unstructured {
	labels := map[string]interface{}{
		SessionIdLabelKey:   sessionID,
		WorkloadNameLabelKey: name,
		SandboxNameLabelKey:  name,
	}

	annotations := map[string]interface{}{
		LastActivityAnnotationKey: time.Now().Format(time.RFC3339),
		IdleTimeoutAnnotationKey:  idleTimeout.String(),
	}

	sandbox := &unstructured.Unstructured{
		Object: map[string]interface{}{
			"apiVersion": "agents.x-k8s.io/v1alpha1",
			"kind":       "Sandbox",
			"metadata": map[string]interface{}{
				"name":        name,
				"namespace":   namespace,
				"labels":      labels,
				"annotations": annotations,
			},
			"spec": map[string]interface{}{
				"template": template.Spec,
				"ttl":      ttl.String(),
				"replicas": 1,
			},
		},
	}

	return sandbox
}

func waitForSandboxRunning(ctx context.Context, watcher chan SandboxStatusUpdate, timeout time.Duration) (interface{}, error) {
	ctx, cancel := context.WithTimeout(ctx, timeout)
	defer cancel()

	select {
	case update := <-watcher:
		if update.Status == "running" {
			return update.Sandbox, nil
		}
		return nil, fmt.Errorf("sandbox failed to start: %s", update.Status)
	case <-ctx.Done():
		return nil, fmt.Errorf("timeout waiting for sandbox to start")
	}
}

func deleteSandboxCR(ctx context.Context, client dynamic.Interface, namespace, name, kind string, timeout time.Duration) error {
	ctx, cancel := context.WithTimeout(ctx, timeout)
	defer cancel()

	var gvr metav1.GroupVersionResource
	switch kind {
	case types.AgentRuntimeKind:
		gvr = metav1.GroupVersionResource{
			Group:    "runtime.agentcube.volcano.sh",
			Version:  "v1alpha1",
			Resource: "agentruntimes",
		}
	case types.CodeInterpreterKind:
		gvr = metav1.GroupVersionResource{
			Group:    "runtime.agentcube.volcano.sh",
			Version:  "v1alpha1",
			Resource: "codeinterpreters",
		}
	default:
		gvr = metav1.GroupVersionResource{
			Group:    "agents.x-k8s.io",
			Version:  "v1alpha1",
			Resource: "sandboxes",
		}
	}

	if err := client.Resource(gvr).Namespace(namespace).Delete(ctx, name, metav1.DeleteOptions{}); err != nil {
		return fmt.Errorf("failed to delete %s %s: %w", kind, name, err)
	}

	klog.Infof("Deleted %s %s/%s", kind, namespace, name)
	return nil
}

func buildEntryPoints(name, namespace string, ports []TargetPort) []types.SandboxEntryPoint {
	entryPoints := make([]types.SandboxEntryPoint, 0, len(ports))
	for _, port := range ports {
		entryPoints = append(entryPoints, types.SandboxEntryPoint{
			Name:     port.Name,
			Port:     port.Port,
			Protocol: string(port.Protocol),
			Path:     fmt.Sprintf("/v1/namespaces/%s/%s/%s", namespace, "code-interpreters", name),
		})
	}
	return entryPoints
}

func getPublicKeyFromEnv() string {
	return os.Getenv("PICOD_PUBLIC_KEY")
}
